from cryptography.fernet import Fernet
import configparser

# using configparser to handle the configuration
config = configparser.ConfigParser()
config.read('app_config.ini')

def generate_key():
    """
    Generate a new key for encryption and store it in the configuration file
    """
    key = Fernet.generate_key()
    config['ENCRYPTION']['Key'] = key.decode()
    with open('app_config.ini', 'w') as configfile:
        config.write(configfile)

def get_key():
    """
    Get the stored key from the configuration file
    """
    return config['ENCRYPTION']['Key'].encode()

def encrypt_credit_card(card_number):
    """
    Encrypt the credit card number using Fernet symmetric encryption
    """
    key = get_key()
    cipher_suite = Fernet(key)
    cipher_text = cipher_suite.encrypt(card_number.encode())
    return cipher_text

def decrypt_credit_card(cipher_text):
    """
    Decrypt the credit card number
    """
    key = get_key()
    cipher_suite = Fernet(key)
    decoded_text = cipher_suite.decrypt(cipher_text)
    return decoded_text.decode()